","replace":"import heapq
def nth_super_ugly_number(n, primes):
    uglies = [2]
    def gen(prime):
        for ugly in uglies:
            yield ugly * prime
    merged = heapq.merge(*map(gen, primes))
    while len(uglies) < n:
